practice_tasks.starter_code:
SELECT id, customer_id, order_date
FROM orders
ORDER BY customer_id, order_date;

practice_tasks.solution:
SELECT id, customer_id, order_date, COUNT(*) OVER (PARTITION BY customer_id) AS total_orders
FROM orders
ORDER BY customer_id, order_date;

challenge.solution:
SELECT name, category, price, MAX(price) OVER (PARTITION BY category) AS max_price
FROM products
ORDER BY category, price DESC;
